  6→// Parse arguments after "run"
  7→const args = process.argv.slice(3);
  8→
  9→function printUsage() {
 10→  console.log("Usage: nexus-cli run [options] <prompt>");
 11→  console.log();
 12→  console.log("Launch a Claude Code agent session and report results.");
 13→  console.log();
 14→  console.log("Arguments:");
 15→  console.log("  <prompt>               The prompt to send to the agent");
 16→  console.log();
 17→  console.log("Options:");
 18→  console.log("  --cwd <dir>            Working directory for the agent session");
 19→  console.log("  --model <model>        Model to use (Claude Code default)");
 20→  console.log("  --max-turns <n>        Maximum number of agentic turns");
 21→  console.log("  --permission-mode <m>  Permission mode (default: bypassPermissions)");
 22→  console.log("  -h, --help             Show this help message");
 23→}
 24→
 25→let prompt = null;
 26→let cwd = process.cwd();
 27→let model = null;
 28→let maxTurns = null;
 29→let permissionMode = "bypassPermissions";
 30→
 31→for (let i = 0; i < args.length; i++) {
 32→  const arg = args[i];
 33→  if (arg === "--help" || arg === "-h") {
 34→    printUsage();
 35→    process.exit(0);
 36→  } else if (arg === "--cwd") {
 37→    cwd = args[++i];
 38→    if (!cwd) {
 39→      process.stderr.write("Error: --cwd requires a directory path\n");
 40→      process.exit(1);
 41→    }
 42→    cwd = path.resolve(cwd);
 43→  } else if (arg === "--model") {
 44→    model = args[++i];
 45→    if (!model) {
 46→      process.stderr.write("Error: --model requires a model name\n");
 47→      process.exit(1);
 48→    }
 49→  } else if (arg === "--max-turns") {
 50→    maxTurns = args[++i];
 51→    if (!maxTurns) {
 52→      process.stderr.write("Error: --max-turns requires a number\n");
 53→      process.exit(1);
 54→    }
 55→  } else if (arg === "--permission-mode") {
 56→    permissionMode = args[++i];
 57→    if (!permissionMode) {
 58→      process.stderr.write("Error: --permission-mode requires a value\n");
 59→      process.exit(1);
 60→    }
 61→  } else if (!arg.startsWith("-")) {
 62→    prompt = arg;
 63→  } else {
 64→    process.stderr.write(`Error: unknown option '${arg}'\n`);
 65→    process.exit(1);
 66→  }
 67→}
 68→
 69→if (!prompt) {
 70→  process.stderr.write("Error: a prompt is required\n\n");
 71→  printUsage();
 72→  process.exit(1);
 73→}
 74→
 75→// Build claude command args
 76→const claudeArgs = [
 77→  "-p",
 78→  "--output-format", "stream-json",
 79→  "--verbose",
 80→  "--include-partial-messages",
 81→  "--no-session-persistence",
 82→  "--permission-mode", permissionMode,
 83→];
 84→
 85→if (model) {
 86→  claudeArgs.push("--model", model);
 87→}
 88→if (maxTurns) {
 89→  claudeArgs.push("--max-turns", maxTurns);
 90→}
 91→
 92→claudeArgs.push(prompt);
 93→
 94→const startTime = Date.now();
 95→
 96→const child = spawn("claude", claudeArgs, {
 97→  cwd,
 98→  stdio: ["ignore", "pipe", "pipe"],
 99→  env: { ...process.env },
100→});
101→
102→let buffer = "";
103→let resultEvent = null;
104→
105→function processLine(line) {
106→  if (!line.trim()) return;
107→
108→  let event;
109→  try {
110→    event = JSON.parse(line);
111→  } catch {
112→    return;
113→  }
114→
115→  if (event.type === "stream_event") {
116→    const inner = event.event;
117→    if (inner && inner.type === "content_block_delta" && inner.delta) {
118→      if (inner.delta.type === "text_delta" && inner.delta.text) {
119→        process.stderr.write(inner.delta.text);
120→      }
121→    } else if (inner && inner.type === "content_block_start" && inner.content_block) {
122→      if (inner.content_block.type === "tool_use") {
123→        process.stderr.write(`\n[tool: ${inner.content_block.name}]\n`);
124→      }
125→    }
126→  } else if (event.type === "assistant") {
127→    // Full assistant message — add a newline after streamed text
128→    const msg = event.message;
129→    if (msg && msg.content) {
130→      for (const block of msg.content) {
131→        if (block.type === "tool_result") {
132→          const preview = typeof block.content === "string"
133→            ? block.content.slice(0, 200)
134→            : "";
135→          if (preview) {
136→            process.stderr.write(`[result: ${preview}${block.content.length > 200 ? "..." : ""}]\n`);
137→          }
138→        }
139→      }
140→    }
141→    process.stderr.write("\n");
142→  } else if (event.type === "result") {
143→    resultEvent = event;
144→  }
145→}
146→
147→child.stdout.on("data", (chunk) => {
148→  buffer += chunk.toString();
149→  const lines = buffer.split("\n");
150→  buffer = lines.pop(); // keep incomplete last line
151→  for (const line of lines) {
152→    processLine(line);
153→  }
154→});
155→
156→// Forward claude's stderr to our stderr
157→child.stderr.on("data", (chunk) => {
158→  process.stderr.write(chunk);
159→});
160→
161→child.on("close", (code) => {
162→  // Process remaining buffer
163→  if (buffer.trim()) {
164→    processLine(buffer);
165→  }
166→
167→  const exitCode = code ?? 1;
168→
169→  if (resultEvent) {
170→    const r = resultEvent;
171→    const report = {
172→      exitCode,
173→      result: r.result || "",
174→      totalCost: r.total_cost_usd || 0,
175→      durationMs: r.duration_ms || (Date.now() - startTime),
176→      numTurns: r.num_turns || 0,
177→      stopReason: r.stop_reason || "unknown",
178→      stopReasonSubtype: r.subtype || "unknown",
179→      usage: {
180→        inputTokens: (r.usage && r.usage.input_tokens) || 0,
181→        outputTokens: (r.usage && r.usage.output_tokens) || 0,
182→        cacheCreationInputTokens: (r.usage && r.usage.cache_creation_input_tokens) || 0,
183→        cacheReadInputTokens: (r.usage && r.usage.cache_read_input_tokens) || 0,
184→      },
185→      modelUsage: formatModelUsage(r.modelUsage || {}),
186→    };
187→    process.stdout.write(JSON.stringify(report, null, 2) + "\n");
188→  } else {
189→    // No result event — produce a fallback report
190→    const report = {
191→      exitCode,
192→      result: "",
193→      totalCost: 0,
194→      durationMs: Date.now() - startTime,
195→      numTurns: 0,
196→      stopReason: "error",
197→      stopReasonSubtype: "process_exit",
198→      usage: {
199→        inputTokens: 0,
200→        outputTokens: 0,
201→        cacheCreationInputTokens: 0,
202→        cacheReadInputTokens: 0,
203→      },
204→      modelUsage: {},
205→    };
206→    process.stdout.write(JSON.stringify(report, null, 2) + "\n");
207→  }
208→
209→  process.exit(exitCode);
210→});
211→
212→child.on("error", (err) => {
213→  const report = {
214→    exitCode: 1,
215→    result: "",
216→    totalCost: 0,
217→    durationMs: Date.now() - startTime,
218→    numTurns: 0,
219→    stopReason: "error",
220→    stopReasonSubtype: "spawn_error",
221→    usage: {
222→      inputTokens: 0,
223→      outputTokens: 0,
224→      cacheCreationInputTokens: 0,
225→      cacheReadInputTokens: 0,
226→    },
227→    modelUsage: {},
228→  };
229→  process.stderr.write(`Error launching claude: ${err.message}\n`);
230→  process.stdout.write(JSON.stringify(report, null, 2) + "\n");
231→  process.exit(1);
232→});
233→
234→function formatModelUsage(raw) {
235→  const result = {};
236→  for (const [key, val] of Object.entries(raw)) {
237→    // Strip context window suffix like [1m] from model name
238→    const cleanKey = key.replace(/\[\d+[km]?\]$/i, "");
239→    result[cleanKey] = {
240→      costUsd: val.costUSD || 0,
241→      inputTokens: val.inputTokens || 0,
242→      outputTokens: val.outputTokens || 0,
243→      cacheCreationInputTokens: val.cacheCreationInputTokens || 0,
244→      cacheReadInputTokens: val.cacheReadInputTokens || 0,
245→    };
246→  }
247→  return result;
248→}
